module decoder_2to4(IN, input_data);
input [1:0] IN;
output reg [3:0] input_data;

always @(*) begin
    case(IN)
        2'b00: input_data = 4'b0001;
        2'b01: input_data = 4'b0010;
        2'b10: input_data = 4'b0100;
        2'b11: input_data = 4'b1000;
        default: input_data = 4'b0000;
    endcase
end

endmodule
